import os
from pip._vendor import pkg_resources
from packaging.specifiers import SpecifierSet
from poetry.core.poetry import Poetry
from subprocess import check_call

def generate_requirements_file():
    """Generate requirements.txt file with hashes"""
    with open('requirements.txt', 'w') as f:
        for dist in pkg_resources.working_set:
            if dist.key not in ['pkg-resources']:  # We exclude pkg-resources because it doesn't have a version
                f.write(f"{dist.key}=={dist.version}\n")

def update_requirements_file():
    """Update requirements.txt file with hashes"""
    os.remove('requirements.txt')  # Remove the existing file
    generate_requirements_file()

def check_dependency_versions():
    """Check if all dependencies are using the same versions across development and production"""
    dev_dependencies = get_dev_dependencies()
    prod_dependencies = get_prod_dependencies()
    
    for dep in dev_dependencies:
        if dep not in prod_dependencies or SpecifierSet(dev_dependencies[dep]) != SpecifierSet(prod_dependencies[dep]):
            return False
            
    return True

def get_dev_dependencies():
    """Get development dependencies from Poetry"""
    poetry = Poetry.create(".")
    return {d: str(v) for d, v in poetry.package.requires}

def get_prod_dependencies():
    """Get production dependencies from requirements.txt file"""
    with open('requirements.txt', 'r') as f:
        lines = [line.strip() for line in f.readlines()]
    
    return {line.split('==')[0]: line.split('==')[1] for line in lines if 'http' not in line}

def update_dependencies():
    """Update development and production dependencies"""
    update_requirements_file()  # Update requirements.txt file with hashes
    check_call(['poetry', 'install'])  # Re-install the Python environment with updated packages